class Solution {
public:
bool solve(int n) {
    vector<bool> isPrime(n + 1, true);
    isPrime[0] = isPrime[1] = false;
    for (int i = 2; i < n; i++)
        if (isPrime[i])
            for (int j = i * i; j <= n; j += i)
                isPrime[j] = false;
    return isPrime;
}
};

int main() {
    int n;
    cin >> n;
    Solution solution;
    vector<bool> isPrime = solution.solve(n);
    for (bool prime : isPrime)
        cout << (prime ? 1 : 0) << ' ';
    cout << endl;
    return 0;
}
